import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./../styles/Auth.css";
import { toast } from "react-toastify"; 
import "react-toastify/dist/ReactToastify.css";

const Login = () => {
  const [libraryId, setLibraryId] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
  
    if (!libraryId || !email || !password) {
      toast.error("All fields are required.", { position: "top-center", autoClose: 3000 });
      return;
    }
  
    const payload = { libraryId, email, password };
    console.log("Request Payload:", payload); // Log request payload
  
    try {
      const response = await fetch("http://localhost:5000/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
  
      const data = await response.json();
      console.log("Response Data:", data); // Log server response
  
      if (response.ok) {
        toast.success("Login Successful ✅", { position: "top-center", autoClose: 3000 });
  
        localStorage.setItem("token", data.token);
        localStorage.setItem("role", email === "ishwaryarajendran77@gmail.com" ? "admin" : "user");
  
        setTimeout(() => {
          navigate("/library");
        }, 3000);
      } else {
        toast.error(data.message || "Invalid credentials or user does not exist.", {
          position: "top-center",
          autoClose: 3000,
        });
      }
    } catch (error) {
      console.error("Error:", error);
      toast.error("Server error. Please try again later.", { position: "top-center", autoClose: 3000 });
    }
  };  

  return (
    <div className="auth-container">
      <div className="auth-box">
        <h2>📚 Library Login</h2>
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Library ID" value={libraryId} onChange={(e) => setLibraryId(e.target.value)} required />
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <button type="submit">Login</button>
        </form>
        <p>New to the library? <span onClick={() => navigate("/signup")}>Sign up</span></p>
      </div>
    </div>
  );
};

export default Login;
